mapper.update:
update clazz
name = #{name}, room = #{room}, begin_date = #{beginDate}, end_date = #{endDate}, master_id = #{masterId}, subject = #{subject}, update_time = #{updateTime},
where id = #{id}

mapper.select:
SELECT c.id, c.name, c.room, c.begin_date, c.end_date, c.master_id, e.name AS masterName, (CASE WHEN CURDATE() > c.end_date THEN '已结课' WHEN CURDATE() < c.begin_date THEN '未开班' ELSE '在读中' END) AS status, c.create_time, c.update_time FROM clazz c LEFT JOIN emp e ON c.master_id = e.id
AND c.name LIKE CONCAT('%',#{name},'%')
AND c.end_date >= #{begin}
AND c.end_date <= #{end}
